      ventas:corte.vD.map(v=>({folio:v.folio,clienteNombre:v.clienteNombre,tipo:v.tipo,formaPago:v.formaPago,total:v.total})),
      abonos:corte.aD.map(a=>({folio:a.folio,clienteNombre:a.clienteNombre,monto:a.monto})),
      gastos:corte.gD.map(g=>({descripcion:g.descripcion,categoriaNombre:g.categoriaNombre,monto:g.monto})),
      porProducto:corte.porProducto,
