    {authErr&&<div style={{background:C.redLight,border:`1px solid ${C.redBorder}`,borderRadius:7,padding:'7px 11px',marginBottom:9,fontSize:11,color:C.red,fontWeight:600}}>❌ {authErr}</div>}
    <div style={{display:'flex',gap:7}}><button onClick={closeModal} style={{...S.btnOutline,flex:1,padding:9,borderRadius:9,fontSize:12}}>Cancelar</button><button onClick={submitAuth} style={{...S.btnDanger,flex:1,padding:9,borderRadius:9,fontSize:12,fontWeight:700}}>🗑 Confirmar</button></div>
